sealed class MePassaFfiException: kotlin.Exception() {
    
    class Identity(
        
        val `details`: kotlin.String
        ) : MePassaFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Crypto(
        
        val `details`: kotlin.String
        ) : MePassaFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Network(
        
        val `details`: kotlin.String
        ) : MePassaFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Storage(
        
        val `details`: kotlin.String
        ) : MePassaFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Protocol(
        
        val `details`: kotlin.String
        ) : MePassaFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Io(
        
        val `details`: kotlin.String
        ) : MePassaFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    
    class Other(
        
        val `details`: kotlin.String
        ) : MePassaFfiException() {
        override val message
            get() = "details=${ `details` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<MePassaFfiException> {
        override fun lift(error_buf: RustBuffer.ByValue): MePassaFfiException = FfiConverterTypeMePassaFfiError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeMePassaFfiError : FfiConverterRustBuffer<MePassaFfiException> {
    override fun read(buf: ByteBuffer): MePassaFfiException {
        

        return when(buf.getInt()) {
            1 -> MePassaFfiException.Identity(
                FfiConverterString.read(buf),
                )
            2 -> MePassaFfiException.Crypto(
                FfiConverterString.read(buf),
                )
            3 -> MePassaFfiException.Network(
                FfiConverterString.read(buf),
                )
            4 -> MePassaFfiException.Storage(
                FfiConverterString.read(buf),
                )
            5 -> MePassaFfiException.Protocol(
                FfiConverterString.read(buf),
                )
            6 -> MePassaFfiException.Io(
                FfiConverterString.read(buf),
                )
            7 -> MePassaFfiException.Other(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: MePassaFfiException): ULong {
        return when(value) {
            is MePassaFfiException.Identity -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is MePassaFfiException.Crypto -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is MePassaFfiException.Network -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is MePassaFfiException.Storage -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is MePassaFfiException.Protocol -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is MePassaFfiException.Io -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
            is MePassaFfiException.Other -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`details`)
            )
        }
    }

    override fun write(value: MePassaFfiException, buf: ByteBuffer) {
        when(value) {
            is MePassaFfiException.Identity -> {
                buf.putInt(1)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is MePassaFfiException.Crypto -> {
                buf.putInt(2)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is MePassaFfiException.Network -> {
                buf.putInt(3)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is MePassaFfiException.Storage -> {
                buf.putInt(4)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is MePassaFfiException.Protocol -> {
                buf.putInt(5)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is MePassaFfiException.Io -> {
                buf.putInt(6)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
            is MePassaFfiException.Other -> {
                buf.putInt(7)
                FfiConverterString.write(value.`details`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




